window.MEDICAL_DATA = {"manifest":{"id":"medical","title":"Medical Emergencies Review — Medical, Behavioral & Geriatric","subtitle":"The Ultimate Provider Course Reviewer","version":"1.0.0","edition":"Aligned with current GINA, ADA, AHA/ASA stroke, and DSM-5-TR guidance; scoped to the NREMT Paramedic Medical/OB-GYN domain","description":"A comprehensive, self-contained study reviewer for adult medical, behavioral, and geriatric emergencies. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, high-yield flashcards, exam-style quiz questions with rationales, realistic scenarios, and comparison tables. Designed for EMTs, paramedics, and nursing/allied-health students preparing for licensing-style cognitive exams (Prometric-administered, NREMT-aligned).","icon":"stethoscope","color":"#2563eb","accentColor":"#e06090","estimatedHours":10,"difficulty":"Intermediate","certification":"EMT/Paramedic licensing exam preparation (Prometric-administered, NREMT-aligned)","examLink":"https://www.nremt.org/","audience":["EMT","Paramedic","Nursing Student","Allied Health Student"],"prerequisites":["BLS provider competency","Basic patient assessment (see EMPACT reviewer)"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Neurological Emergencies I — Stroke & TIA","section":"Neurological","difficulty":"Intermediate"},{"id":"c02","number":2,"title":"Neurological Emergencies II — Seizures & Altered Mental Status","section":"Neurological","difficulty":"Intermediate"},{"id":"c03","number":3,"title":"Endocrine Emergencies — Hypoglycemia, DKA & HHS","section":"Endocrine","difficulty":"Advanced"},{"id":"c04","number":4,"title":"Respiratory Medical Emergencies — Asthma & COPD","section":"Respiratory","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Obstetric Medical Emergencies — Preeclampsia & Eclampsia","section":"Medical/OB","difficulty":"Intermediate"},{"id":"c06","number":6,"title":"Behavioral Emergencies I — Assessment & De-escalation","section":"Behavioral","difficulty":"Beginner to Intermediate"},{"id":"c07","number":7,"title":"Behavioral Emergencies II — Psychotic & Mood Disorders","section":"Behavioral","difficulty":"Intermediate"},{"id":"c08","number":8,"title":"Behavioral Emergencies III — Personality, Substance-Related & High-Risk Presentations","section":"Behavioral","difficulty":"Advanced"},{"id":"c09","number":9,"title":"Geriatric Emergencies I — Delirium vs. Dementia & Atypical Presentations","section":"Geriatric","difficulty":"Intermediate"},{"id":"c10","number":10,"title":"Geriatric Emergencies II — Polypharmacy, Falls & Elder Abuse Recognition","section":"Geriatric","difficulty":"Intermediate"},{"id":"c11","number":11,"title":"Toxicological & Environmental Medical Presentations","section":"Toxicology","difficulty":"Intermediate"},{"id":"c12","number":12,"title":"Sepsis, GI/Renal Emergencies & General Medical Red Flags","section":"Medical","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Neurological Emergencies I — Stroke & TIA","shortTitle":"Stroke & TIA","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Distinguish stroke from TIA and explain why prehospital care treats both as time-critical.","Differentiate ischemic from hemorrhagic stroke and its field-relevant implications.","Apply a validated prehospital stroke scale to recognize likely stroke.","Recognize findings suggestive of a large-vessel occlusion (LVO) stroke.","Describe field priorities: last-known-well time, glucose check, and rapid transport/notification."],"summary":[{"title":"Stroke vs. TIA — Same Urgency, Different Duration","content":"A stroke is an acute disruption of blood flow to the brain causing neurologic deficit; a transient ischemic attack (TIA) produces the same type of deficit but resolves completely, classically within minutes to an hour, without lasting tissue injury on imaging. Because a TIA cannot be reliably distinguished from an evolving stroke in the field — and because TIA carries a significant short-term risk of a subsequent completed stroke — both are treated with the same urgency: rapid recognition, rapid transport, and rapid hospital notification."},{"title":"Ischemic vs. Hemorrhagic Stroke","content":"Ischemic stroke (the large majority of strokes) results from a clot or other obstruction blocking blood flow; hemorrhagic stroke results from bleeding into or around brain tissue. The two cannot be reliably distinguished in the field by symptoms alone — both cause focal neurologic deficits — which is why field care focuses on rapid recognition and transport rather than attempting to guess the stroke type, leaving that determination to hospital imaging."},{"title":"Validated Prehospital Stroke Scales","content":"The Cincinnati Prehospital Stroke Scale (CPSS) checks three findings — facial droop, arm drift, and speech abnormality — and is widely taught as the entry-level prehospital screening tool. Other validated scales add sensitivity for detecting a large-vessel occlusion (LVO), which may change the destination decision in systems with endovascular-capable centers: the Los Angeles Prehospital Stroke Screen (LAPSS), RACE (Rapid Arterial oCclusion Evaluation), and FAST-ED (which adds eye deviation and denial/neglect to the FAST components). Current stroke guidance continues to endorse using a validated scale for prehospital stroke recognition and LVO screening, with the specific scale and any destination threshold set by the local EMS system."},{"title":"Recognizing Possible Large-Vessel Occlusion","content":"Findings that raise suspicion for LVO stroke — beyond a simple facial droop/arm drift/speech finding — include gaze deviation toward one side, severe unilateral weakness affecting both the face and arm together, and neglect/denial of the deficit (the patient not recognizing or acknowledging a weak limb). Systems with access to an endovascular-capable stroke center may use an LVO-screening scale to decide whether to bypass a closer, non-endovascular-capable hospital, per local protocol."},{"title":"Field Priorities","content":"Once stroke is suspected: determine and document the last-known-well time precisely (this drives eligibility for time-sensitive hospital treatments), check blood glucose (hypoglycemia is a well-known stroke mimic and is rapidly correctable), perform a validated stroke scale, and transport rapidly with early hospital notification (a 'stroke alert') so the receiving facility can prepare. Avoid delaying transport for a full neurologic exam beyond the screening scale — time is the central variable in stroke outcome."}],"clinicalPearls":["TIA and stroke get the same field urgency — a resolved deficit does not rule out a serious ongoing process.","Field care cannot reliably distinguish ischemic from hemorrhagic stroke — treat both as time-critical and let hospital imaging sort it out.","Always check glucose in a suspected stroke patient — hypoglycemia is a correctable stroke mimic.","Last-known-well time is one of the single most important pieces of information you can gather and document."],"redFlags":["Any new focal neurologic deficit (facial droop, arm drift, speech abnormality), even if it has since resolved.","Gaze deviation, severe unilateral face+arm weakness, or neglect of a weak limb — possible LVO.","An unclear or unknown last-known-well time — document what is known and keep gathering it en route."],"commonMistakes":["Dismissing a resolved deficit (possible TIA) as no longer urgent.","Failing to check glucose before assuming a deficit is purely neurologic.","Delaying transport to complete an extensive neurologic exam instead of a rapid validated screening scale."],"memoryAids":["FAST: Face, Arm, Speech, Time.","TIA = stroke symptoms that resolved, not a stroke that didn't happen — same urgency.","Glucose first — a fast, correctable stroke mimic.","Time is brain — last-known-well time drives everything downstream."],"decisionTrees":[{"title":"Suspected Stroke Field Approach","content":"Focal neurologic deficit noted (current or recently resolved)\n  → Check blood glucose → treat hypoglycemia per protocol if present, reassess\n  → Determine and document last-known-well time precisely\n  → Perform validated prehospital stroke scale (e.g., CPSS ± LVO-screening scale per local protocol)\n  → Positive screen → early hospital notification ('stroke alert'), rapid transport per local destination protocol (nearest stroke center vs. EVT-capable center bypass, per LVO screen and system design)\n  → Continue serial reassessment en route; do not delay transport for an extensive exam"}],"references":["2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke","Cincinnati Prehospital Stroke Scale (CPSS); RACE and FAST-ED as examples of LVO-screening scales"]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What is a TIA?","answer":"A transient ischemic attack — stroke-like neurologic deficit that resolves completely, classically within minutes to an hour, without lasting tissue injury.","category":"Stroke"},{"id":"c01_fc02","question":"Why is a TIA treated with the same urgency as a stroke in the field?","answer":"It cannot be reliably distinguished from an evolving stroke in the field, and it carries a significant short-term risk of a subsequent completed stroke.","category":"Stroke"},{"id":"c01_fc03","question":"What are the two broad categories of stroke?","answer":"Ischemic (clot/obstruction blocking blood flow) and hemorrhagic (bleeding into or around brain tissue).","category":"Stroke"},{"id":"c01_fc04","question":"Can ischemic and hemorrhagic stroke be reliably distinguished by field symptoms alone?","answer":"No — both cause focal neurologic deficits; the distinction is made by hospital imaging.","category":"Stroke"},{"id":"c01_fc05","question":"What three findings does the Cincinnati Prehospital Stroke Scale (CPSS) check?","answer":"Facial droop, arm drift, and speech abnormality.","category":"Stroke Scales"},{"id":"c01_fc06","question":"Name two prehospital stroke scales beyond CPSS that add sensitivity for detecting large-vessel occlusion (LVO).","answer":"LAPSS (Los Angeles Prehospital Stroke Screen) and RACE (Rapid Arterial oCclusion Evaluation); FAST-ED is another example.","category":"Stroke Scales"},{"id":"c01_fc07","question":"What does FAST-ED add to the standard FAST components?","answer":"Eye deviation and denial/neglect.","category":"Stroke Scales"},{"id":"c01_fc08","question":"What findings raise suspicion for a large-vessel occlusion (LVO) stroke?","answer":"Gaze deviation toward one side, severe unilateral weakness affecting both face and arm together, and neglect/denial of the deficit.","category":"Stroke"},{"id":"c01_fc09","question":"Why might an LVO-screening scale change the destination decision?","answer":"In systems with an endovascular-capable stroke center, a positive LVO screen may justify bypassing a closer, non-endovascular-capable hospital, per local protocol.","category":"Stroke"},{"id":"c01_fc10","question":"Why is checking blood glucose a field priority in suspected stroke?","answer":"Hypoglycemia is a well-known, rapidly correctable stroke mimic.","category":"Field Management"},{"id":"c01_fc11","question":"Why is the last-known-well time so important to document precisely?","answer":"It drives eligibility for time-sensitive hospital treatments.","category":"Field Management"},{"id":"c01_fc12","question":"What is a 'stroke alert'?","answer":"Early hospital notification of a suspected stroke patient so the receiving facility can prepare.","category":"Field Management"},{"id":"c01_fc13","question":"Should transport be delayed to complete an extensive neurologic exam in suspected stroke?","answer":"No — use a rapid validated screening scale and prioritize rapid transport; time is the central variable in stroke outcome.","category":"Field Management"},{"id":"c01_fc14","question":"What is the 2026 guideline governing stroke management referenced in this course?","answer":"The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke.","category":"Guidelines"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"What defines a TIA (transient ischemic attack)?","options":["A. A stroke that leaves permanent deficits","B. Stroke-like neurologic deficit that resolves completely, classically within minutes to an hour","C. A minor headache with no neurologic findings","D. A seizure followed by confusion"],"correct":1,"rationale":"A TIA produces stroke-like focal neurologic deficit that resolves completely without lasting tissue injury, classically within minutes to an hour.","difficulty":"Easy"},{"id":"c01_q02","question":"Why is a TIA treated with the same field urgency as an ongoing stroke?","options":["A. It cannot be reliably distinguished from an evolving stroke in the field, and carries short-term risk of a completed stroke","B. TIAs are more dangerous than strokes","C. TIA is simply an outdated term for stroke","D. There is no urgency difference because TIAs are never serious"],"correct":0,"rationale":"Because a TIA can't be reliably distinguished from an evolving stroke in the field, and TIA patients face a meaningful short-term risk of a subsequent completed stroke, both are managed with the same urgency.","difficulty":"Medium"},{"id":"c01_q03","question":"What are the two broad categories of stroke?","options":["A. Ischemic and hemorrhagic","B. Acute and chronic","C. Central and peripheral","D. Primary and secondary"],"correct":0,"rationale":"Stroke is broadly categorized as ischemic (obstruction of blood flow) or hemorrhagic (bleeding into/around brain tissue).","difficulty":"Easy"},{"id":"c01_q04","question":"Can ischemic and hemorrhagic stroke be reliably distinguished in the field by symptoms alone?","options":["A. Yes, symptoms are always distinct","B. No — both cause focal neurologic deficits; imaging is needed to distinguish them","C. Only hemorrhagic stroke causes a facial droop","D. Only ischemic stroke causes speech abnormality"],"correct":1,"rationale":"Field symptoms cannot reliably distinguish the two stroke types; both produce focal neurologic deficits, and hospital imaging is required to differentiate them.","difficulty":"Medium"},{"id":"c01_q05","question":"What three findings does the Cincinnati Prehospital Stroke Scale (CPSS) assess?","options":["A. Facial droop, arm drift, speech abnormality","B. Blood pressure, heart rate, respiratory rate","C. Pupil size, gag reflex, grip strength","D. Gaze deviation, neglect, ataxia"],"correct":0,"rationale":"CPSS checks facial droop, arm drift, and speech abnormality as its three core findings.","difficulty":"Easy"},{"id":"c01_q06","question":"What is the purpose of an LVO-screening scale like RACE or FAST-ED?","options":["A. To diagnose the exact stroke type in the field","B. To add sensitivity for detecting a large-vessel occlusion, which may inform destination decisions","C. To replace blood glucose checks","D. To determine the patient's code status"],"correct":1,"rationale":"LVO-screening scales add sensitivity for detecting large-vessel occlusion strokes, which may influence a destination decision toward an endovascular-capable center per local protocol.","difficulty":"Medium"},{"id":"c01_q07","question":"What does FAST-ED add to the standard FAST components?","options":["A. Eye deviation and denial/neglect","B. Blood glucose and temperature","C. Pupil reactivity","D. Grip strength bilaterally"],"correct":0,"rationale":"FAST-ED extends FAST by adding eye (gaze) deviation and denial/neglect to improve LVO detection sensitivity.","difficulty":"Medium"},{"id":"c01_q08","question":"Which findings raise suspicion for a large-vessel occlusion (LVO) stroke?","options":["A. Isolated mild facial droop only","B. Gaze deviation, severe combined face+arm weakness, and neglect of the deficit","C. A resolved speech abnormality with normal exam otherwise","D. Isolated numbness without weakness"],"correct":1,"rationale":"Gaze deviation, severe unilateral face+arm weakness together, and neglect/denial of the deficit are findings that raise LVO suspicion beyond a basic FAST-positive screen.","difficulty":"Hard"},{"id":"c01_q09","question":"Why should blood glucose be checked in a suspected stroke patient?","options":["A. Hypoglycemia is a well-known, rapidly correctable stroke mimic","B. Glucose has no relevance to neurologic presentations","C. It replaces the need for a stroke scale","D. It is only relevant in diabetic patients"],"correct":0,"rationale":"Hypoglycemia can mimic a focal neurologic deficit and is rapidly correctable, making a glucose check a high-value field step in suspected stroke.","difficulty":"Medium"},{"id":"c01_q10","question":"Why is documenting the last-known-well time so important?","options":["A. It drives eligibility for time-sensitive hospital treatments","B. It is only used for billing purposes","C. It has no bearing on hospital treatment decisions","D. It replaces the need for a stroke scale"],"correct":0,"rationale":"Last-known-well time is a key driver of eligibility for time-sensitive interventions at the receiving hospital, making precise documentation a high priority.","difficulty":"Medium"},{"id":"c01_q11","question":"What is a 'stroke alert'?","options":["A. A patient-initiated emergency call","B. Early hospital notification of a suspected stroke patient so the receiving facility can prepare","C. A specific stroke medication","D. A type of cardiac monitor alarm"],"correct":1,"rationale":"A stroke alert is early notification to the receiving hospital, allowing the stroke team to prepare before patient arrival.","difficulty":"Easy"},{"id":"c01_q12","question":"Should transport be delayed to perform a full, extensive neurologic exam on a suspected stroke patient?","options":["A. Yes, always complete a full exam before transport","B. No — use a rapid validated screening scale and prioritize rapid transport, since time is central to stroke outcome","C. Only if the patient requests it","D. Only for hemorrhagic strokes"],"correct":1,"rationale":"Time is the central variable in stroke outcomes, so field care uses a rapid screening scale rather than delaying transport for an extensive exam.","difficulty":"Medium"},{"id":"c01_q13","question":"A patient had left-sided facial droop and slurred speech that fully resolved 20 minutes before EMS arrival. How should this be treated?","options":["A. As a non-urgent complaint since symptoms resolved","B. With the same urgency as an active stroke, given the possibility of TIA and risk of a subsequent stroke","C. Only urgent if the patient becomes symptomatic again","D. As a psychiatric complaint given full resolution"],"correct":1,"rationale":"A resolved deficit consistent with TIA still carries meaningful short-term stroke risk and should be treated with full stroke-protocol urgency.","difficulty":"Hard"},{"id":"c01_q14","question":"A stroke patient has gaze deviation to the right, severe right face and arm weakness, and does not acknowledge the weak arm. What should this presentation raise suspicion for?","options":["A. A simple TIA with no further workup needed","B. Possible large-vessel occlusion (LVO) stroke, potentially warranting an LVO-screening-based destination decision","C. A hypoglycemic event with no stroke involvement","D. A behavioral/psychiatric emergency"],"correct":1,"rationale":"Gaze deviation, combined severe face+arm weakness, and neglect of the deficit are classic LVO-suspicious findings that may change the transport destination decision per local protocol.","difficulty":"Hard"},{"id":"c01_q15","question":"Which guideline is the authoritative current source for stroke management referenced in this course?","options":["A. The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke","B. GINA 2025","C. DSM-5-TR","D. ADA Standards of Care 2026"],"correct":0,"rationale":"The 2026 AHA/ASA Guideline for the Early Management of Patients With Acute Ischemic Stroke is the current authoritative source, replacing the 2018/2019 guideline.","difficulty":"Easy"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"The Resolved Deficit","presentation":"A 68-year-old man had sudden right-sided facial droop and slurred speech about 40 minutes ago while at a family lunch. By the time EMS arrives, his speech is clear and his face appears symmetric. He feels fine and wants to cancel the ambulance.","vitals":{"bp":"148/86 mmHg","hr":"78 bpm","glucose":"98 mg/dL","exam":"Currently normal facial symmetry and speech"},"question":"What is the appropriate approach to this patient?","options":["A: Cancel transport since the exam is now normal.","B: Treat this as a possible TIA with the same urgency as an active stroke, document the last-known-well/onset time precisely, and transport with hospital notification.","C: Advise the patient to see his primary doctor within the week.","D: Transport only if symptoms recur during the encounter."],"correct":1,"explanation":"A resolved facial droop and speech abnormality is classic for a possible TIA, which cannot be reliably distinguished from an evolving stroke in the field and carries meaningful short-term risk of a subsequent completed stroke. This should be treated with the same urgency as an active stroke, with precise onset-time documentation and prompt transport.","clinicalPearl":"A resolved deficit is not a reason to relax — it's a reason to document the timeline precisely and transport with full urgency."},{"id":"c01_s02","title":"Confusion With a Normal Glucose Twist","presentation":"A 74-year-old woman is found by family with new left arm weakness and confusion. Initial impression suggests possible stroke. On scene, her blood glucose reads 42 mg/dL.","vitals":{"bp":"132/78 mmHg","hr":"92 bpm","glucose":"42 mg/dL","exam":"Left arm weakness, confusion"},"question":"What is the correct next step?","options":["A: Proceed directly to stroke-alert transport without addressing the glucose value.","B: Treat the hypoglycemia per protocol first, since it is a well-known, rapidly correctable stroke mimic, and reassess neurologic status afterward.","C: Ignore the glucose reading since the presentation looks like a clear stroke.","D: Withhold treatment until arrival at the hospital."],"correct":1,"explanation":"Hypoglycemia is a well-known stroke mimic that is rapidly correctable in the field. Treating the hypoglycemia and reassessing neurologic status is the correct next step before finalizing the working diagnosis and destination decision — a focal deficit that resolves with glucose correction is not treated as a stroke alert.","clinicalPearl":"Always check glucose before you commit to a stroke diagnosis in the field — a fixable stroke mimic can save this patient a stroke-center transport they don't need."},{"id":"c01_s03","title":"Gaze Deviation and Neglect","presentation":"A 59-year-old man has sudden onset of right gaze deviation, severe left face and arm weakness, and does not acknowledge that his left arm is weak when asked. Local EMS protocol uses an LVO-screening scale to determine bypass eligibility to an endovascular-capable stroke center.","vitals":{"bp":"168/94 mmHg","hr":"88 bpm","glucose":"110 mg/dL","exam":"Gaze deviation, severe left face+arm weakness, neglect of left arm"},"question":"What should this constellation of findings prompt?","options":["A: A routine transport to the nearest hospital regardless of capability.","B: Application of the LVO-screening scale per protocol, since these findings (gaze deviation, combined severe face+arm weakness, neglect) suggest possible large-vessel occlusion, potentially justifying bypass to an endovascular-capable center.","C: Assumption that this cannot be a stroke because the deficit is too severe.","D: Delaying the stroke alert until arrival at the hospital."],"correct":1,"explanation":"Gaze deviation, severe combined face and arm weakness, and neglect of the affected limb are LVO-suspicious findings. Per local protocol using an LVO-screening scale, this presentation may justify bypassing a closer, non-endovascular-capable hospital in favor of an endovascular-capable stroke center.","clinicalPearl":"Gaze deviation plus neglect plus severe combined weakness is the pattern that makes an LVO-screening scale worth applying — it can change where this patient needs to go."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"Suspected Stroke Field Recognition and Transport Decision","description":"Sequence for recognizing suspected stroke, ruling out a correctable mimic, and deciding on transport destination.","steps":["Identify a new focal neurologic deficit (current or recently resolved) using a validated stroke scale (e.g., CPSS: facial droop, arm drift, speech abnormality).","Check blood glucose immediately; treat hypoglycemia per protocol if present and reassess neurologic status.","Determine and precisely document the last-known-well time from the patient/bystanders.","Assess for LVO-suspicious findings (gaze deviation, severe combined face+arm weakness, neglect/denial) using a local LVO-screening scale if available.","Provide early hospital notification ('stroke alert') so the receiving facility can prepare.","Transport per local destination protocol — nearest stroke-capable hospital, or bypass to an endovascular-capable center if LVO screen is positive and system design supports it.","Reassess neurologic status serially en route without delaying transport for an extensive exam."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"Prehospital Stroke Scale Comparison","headers":["Scale","What It Adds","Components Checked","Primary Use"],"rows":[["CPSS (Cincinnati Prehospital Stroke Scale)","Baseline stroke screening","Facial droop, arm drift, speech abnormality","General stroke recognition"],["LAPSS (Los Angeles Prehospital Stroke Screen)","Adds exclusion criteria (age, glucose, symptom duration, prior seizure/wheelchair history)","Facial droop, grip strength, arm drift, plus exclusion criteria","General stroke recognition with mimic screening"],["RACE (Rapid Arterial oCclusion Evaluation)","Adds LVO-sensitive items","Facial palsy, arm motor, leg motor, gaze deviation, aphasia/agnosia","Large-vessel occlusion (LVO) screening"],["FAST-ED","Adds eye deviation and denial/neglect to FAST","Face, Arm, Speech, Time + Eye deviation, Denial/neglect","Large-vessel occlusion (LVO) screening"]]},{"id":"c01_t02","title":"Ischemic vs. Hemorrhagic Stroke — Field Perspective","headers":["Feature","Ischemic Stroke","Hemorrhagic Stroke"],"rows":[["Mechanism","Obstruction (clot) blocking blood flow","Bleeding into or around brain tissue"],["Relative frequency","Majority of strokes","Minority of strokes"],["Field distinguishability by symptoms","Not reliably distinguishable from hemorrhagic by symptoms alone","Not reliably distinguishable from ischemic by symptoms alone"],["Determination method","Hospital imaging (CT/MRI)","Hospital imaging (CT/MRI)"],["Field priority","Same: recognize, check glucose, document LKW time, transport rapidly","Same: recognize, check glucose, document LKW time, transport rapidly"]]}]}}};
